import{_ as a,o as n,c as t,a4 as i}from"./chunks/framework.PZCYvDoh.js";const p="/XIAOHUANG_BLOG/assets/image-20260619104659174.B6qH9GH-.png",g=JSON.parse('{"title":"PX4 Ubuntu教程","description":"","frontmatter":{},"headers":[],"relativePath":"docs/硬件资料/旋翼无人机/PX4与Ubuntu教程/PX4_Ubuntu教程.md","filePath":"docs/硬件资料/旋翼无人机/PX4与Ubuntu教程/PX4_Ubuntu教程.md"}'),o={name:"docs/硬件资料/旋翼无人机/PX4与Ubuntu教程/PX4_Ubuntu教程.md"};function e(l,s,c,d,u,r){return n(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="px4-ubuntu教程" tabindex="-1">PX4 Ubuntu教程 <a class="header-anchor" href="#px4-ubuntu教程" aria-label="Permalink to &quot;PX4 Ubuntu教程&quot;">​</a></h1><h2 id="mid360教程" tabindex="-1">mid360教程 <a class="header-anchor" href="#mid360教程" aria-label="Permalink to &quot;mid360教程&quot;">​</a></h2><p>mid360快速使用指南： <a href="PX4_Ubuntu%E6%95%99%E7%A8%8B.assets%5CLivox_Mid-360_Quick_Start_Guide_multi.pdf">Livox_Mid-360_Quick_Start_Guide_multi.pdf</a></p><p>mid360上位机使用指南： <a href="PX4_Ubuntu%E6%95%99%E7%A8%8B.assets%5CLivox_Viewer_2_User_Manual_chs_v1.2.pdf">Livox_Viewer_2_User_Manual_chs_v1.2.pdf</a></p><h3 id="设置静态ip驱动上位机" tabindex="-1">设置静态IP驱动上位机 <a class="header-anchor" href="#设置静态ip驱动上位机" aria-label="Permalink to &quot;设置静态IP驱动上位机&quot;">​</a></h3><ol><li><p><strong>打开“网络连接”窗口</strong></p><ul><li>按下键盘快捷键 <code>Win + R</code>，输入 <code>ncpa.cpl</code>，然后点击“确定”。</li><li>或者：右键点击任务栏右下角的网络图标 → 选择“打开网络和 Internet 设置” → 点击“更改适配器选项”。</li></ul></li><li><p><strong>找到您正在使用的网卡</strong></p><ul><li>通常名为“以太网”或“本地连接”。如果使用的是 USB 转网口，可能会显示为“Realtek USB GbE Family”等。</li><li>确认网线已连接 Livox 设备。</li></ul></li><li><p><strong>打开网卡属性</strong></p><ul><li>右键点击该网卡 → 选择 <strong>“属性”</strong>。</li></ul></li><li><p><strong>选择 Internet 协议版本 4 (TCP/IPv4)</strong></p><ul><li>在列表中双击 <strong>“Internet 协议版本 4 (TCP/IPv4)”</strong> 或选中后点击“属性”。</li></ul></li><li><p><strong>填写静态 IP 地址</strong></p><ul><li><p>选择 <strong>“使用下面的 IP 地址”</strong>。</p></li><li><p>在对应框中输入：</p><p>text</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IP 地址：192.168.1.2</span></span>
<span class="line"><span>子网掩码：255.255.255.0</span></span>
<span class="line"><span>默认网关：192.168.1.1</span></span></code></pre></div></li><li><p><strong>首选 DNS 服务器</strong> 可以留空，或填 <code>8.8.8.8</code>（不影响设备通信）。</p></li></ul></li><li><p><strong>确认并保存</strong></p><ul><li>依次点击“确定” → “关闭”。</li><li>设置立即生效，无需重启电脑。</li></ul></li><li><p><strong>验证（可选）</strong></p><ul><li>打开命令提示符（<code>Win + R</code> → 输入 <code>cmd</code> → 回车）。</li><li>输入 <code>ipconfig</code>，查看对应网卡是否显示上述 IP 地址。</li></ul></li></ol><h3 id="驱动配置" tabindex="-1">驱动配置 <a class="header-anchor" href="#驱动配置" aria-label="Permalink to &quot;驱动配置&quot;">​</a></h3><p>教程：<a href="http://www.lryc.cn/news/266645.html?action=onClick" target="_blank" rel="noreferrer">Ubuntu 20.04使用Livox Mid-360</a></p><p>教程：<a href="https://blog.csdn.net/2301_79618994/article/details/150475756" target="_blank" rel="noreferrer">使用ros2跑mid360的fastlio2算法详细教程_mid360 ros2-CSDN博客</a></p><p><strong>完整流程</strong></p><h4 id="linux硬件驱动安装" tabindex="-1">linux硬件驱动安装 <a class="header-anchor" href="#linux硬件驱动安装" aria-label="Permalink to &quot;linux硬件驱动安装&quot;">​</a></h4><p>安装CMAKE库<code>$ sudo apt install cmake</code></p><p>然后用下面的代码，确认一下gcc版本大于4.8.1</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gcc </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">v</span></span></code></pre></div><p>执行如下命令克隆、编译、安装库。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git clone https://github.com/Livox-SDK/Livox-SDK2.git</span></span>
<span class="line"><span>cd ./Livox-SDK2/</span></span>
<span class="line"><span>mkdir build</span></span>
<span class="line"><span>cd build</span></span>
<span class="line"><span>cmake .. &amp;&amp; make -j</span></span>
<span class="line"><span>sudo make install</span></span></code></pre></div><h4 id="ros2驱动安装" tabindex="-1">ros2驱动安装 <a class="header-anchor" href="#ros2驱动安装" aria-label="Permalink to &quot;ros2驱动安装&quot;">​</a></h4><p>在linux硬件安装的基础上安装ros2的驱动</p><p>新建ros_ws文件夹作为ROS2的工作目录，并在目录下新建src文件存放套件源码</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mkdir -p ros_ws/src/</span></span>
<span class="line"><span>cd ros_ws/src/</span></span></code></pre></div><p>克隆livox_ros_driver2 到src目录</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git clone https://github.com/Livox-SDK/livox_ros_driver2.git</span></span></code></pre></div><p>编译驱动</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>source /opt/ros/humble/setup.sh</span></span>
<span class="line"><span>./build.sh humble</span></span></code></pre></div><p>~/mid360/ros_ws/src/livox_ros_driver2一般在这个目录下可以找到build.sh</p><p><strong>修改，ros_ws/install/livox_ros_driver2/share/livox_ros_driver2/config/MID360_config.json</strong>中的本机ip 和设备ip</p><ul><li><strong><code>host_net_info</code> 下所有 IP</strong>：填 Orange Pi <strong>有线网卡</strong>的 IP（<code>192.168.1.50</code>）</li><li><strong><code>lidar_configs</code> 下的 <code>&quot;ip&quot;</code></strong>：填雷达实际 IP（<code>192.168.1.195</code>）</li><li><strong>注意检查</strong><code>src</code> 和 <code>install</code> 两个目录下的配置文件需同步修改，修改后需重新编译。</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;lidar_summary_info&quot; : {</span></span>
<span class="line"><span>    &quot;lidar_type&quot;: 8</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>  &quot;MID360&quot;: {</span></span>
<span class="line"><span>    &quot;lidar_net_info&quot; : {</span></span>
<span class="line"><span>      &quot;cmd_data_port&quot;: 56100,</span></span>
<span class="line"><span>      &quot;push_msg_port&quot;: 56200,</span></span>
<span class="line"><span>      &quot;point_data_port&quot;: 56300,</span></span>
<span class="line"><span>      &quot;imu_data_port&quot;: 56400,</span></span>
<span class="line"><span>      &quot;log_data_port&quot;: 56500</span></span>
<span class="line"><span>    },</span></span>
<span class="line"><span>    &quot;host_net_info&quot; : {</span></span>
<span class="line"><span>      &quot;cmd_data_ip&quot; : &quot;192.168.1.50&quot;,//网口ip</span></span>
<span class="line"><span>      &quot;cmd_data_port&quot;: 56101,</span></span>
<span class="line"><span>      &quot;push_msg_ip&quot;: &quot;192.168.1.50&quot;,</span></span>
<span class="line"><span>      &quot;push_msg_port&quot;: 56201,</span></span>
<span class="line"><span>      &quot;point_data_ip&quot;: &quot;192.168.1.50&quot;,</span></span>
<span class="line"><span>      &quot;point_data_port&quot;: 56301,</span></span>
<span class="line"><span>      &quot;imu_data_ip&quot; : &quot;192.168.1.50&quot;,</span></span>
<span class="line"><span>      &quot;imu_data_port&quot;: 56401,</span></span>
<span class="line"><span>      &quot;log_data_ip&quot; : &quot;&quot;,</span></span>
<span class="line"><span>      &quot;log_data_port&quot;: 56501</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>  &quot;lidar_configs&quot; : [</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      &quot;ip&quot; : &quot;192.168.1.195&quot;,//雷达ip,最后俩位查看雷达的sn码来修改</span></span>
<span class="line"><span>      &quot;pcl_data_type&quot; : 1,</span></span>
<span class="line"><span>      &quot;pattern_mode&quot; : 0,</span></span>
<span class="line"><span>      &quot;extrinsic_parameter&quot; : {</span></span>
<span class="line"><span>        &quot;roll&quot;: 0.0,</span></span>
<span class="line"><span>        &quot;pitch&quot;: 0.0,</span></span>
<span class="line"><span>        &quot;yaw&quot;: 0.0,</span></span>
<span class="line"><span>        &quot;x&quot;: 0,</span></span>
<span class="line"><span>        &quot;y&quot;: 0,</span></span>
<span class="line"><span>        &quot;z&quot;: 0</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  ]</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>驱动代码</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>source ../../install/setup.sh</span></span>
<span class="line"><span>ros2 launch livox_ros_driver2 rviz_MID360_launch.py</span></span></code></pre></div><p>运行之后就可以得到点云图。</p><img src="https://i-blog.csdnimg.cn/direct/5debc46b85eb4ca68e7ca6a76232db2c.png" alt="img" style="zoom:25%;"><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><p><strong>编译 Livox-SDK2 时进程被 Killed</strong></p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>增大交换空间（参考ROS2博客）</p></div></div><h3 id="fastlio2算法包" tabindex="-1">fastlio2算法包 <a class="header-anchor" href="#fastlio2算法包" aria-label="Permalink to &quot;fastlio2算法包&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd ros_ws/src # cd into a ros2 workspace folder</span></span>
<span class="line"><span>git clone https://github.com/Ericsii/FAST_LIO.git --recursive</span></span>
<span class="line"><span>cd ..</span></span>
<span class="line"><span>rosdep install --from-paths src --ignore-src -y</span></span>
<span class="line"><span>colcon build --symlink-install     //务必使用这个来编译，其他指令很容易报错</span></span></code></pre></div><p><strong>编译 FAST-LIO2</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd ~/px4_mid360_project/mid360_fastlio_ws</span></span>
<span class="line"><span>colcon build --packages-select fast_lio</span></span>
<span class="line"><span>source install/setup.bash</span></span></code></pre></div><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><p><strong>Fastlio2不支持PointCloud2格式数据</strong></p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>修改 <code>mid360.yaml</code> 配置文件中的 <code>lidar_type</code></strong></p><p>将 <code>lidar_type</code> 从 <code>1</code>（Livox CustomMsg）改为 <code>2</code>（Velodyne/通用 PointCloud2 格式）</p></div></div><p><strong>启动命令与 RViz2 设置</strong></p><ul><li><p><strong>启动雷达驱动</strong>（需指定 <code>xfer_format:=0</code> 以输出标准 PointCloud2）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> livox_ros_driver2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rviz_MID360.launch.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xfer_format:=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span></code></pre></div></li><li><p><strong>启动 FAST-LIO 算法</strong>（另开终端）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ros2 launch fast_lio mapping.launch.py</span></span></code></pre></div></li><li><p><code>ros2 topic hz /livox/lidar</code> 显示非零频率（如 10Hz）</p></li></ul><h3 id="网络配置" tabindex="-1">网络配置 <a class="header-anchor" href="#网络配置" aria-label="Permalink to &quot;网络配置&quot;">​</a></h3><p>重要工具：<strong>wireshake</strong></p><p><strong>网络分工</strong>：</p><ul><li><strong>WiFi (wlan0)</strong>：连接外网，用于 SSH 远程调试，IP：<code>192.168.1.12</code></li><li><strong>有线网卡 (eth0)</strong>：直连雷达，专用于接收点云数据，IP：<code>192.168.1.50</code></li><li><strong>雷达 IP</strong>：<code>192.168.1.195</code>（通过 Windows 上位机 Livox Viewer 2 修改）</li></ul><img src="`+p+`" alt="image-20260619104659174" style="zoom:25%;"><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p><strong>注意使用mid360上位机修改mid360ip后，不要再次用上位机连接，ip会被重置的</strong></p></div><p>网络先后顺序配置</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo nmcli connection modify &quot;Wired connection 1&quot; ipv4.route-metric 200</span></span>
<span class="line"><span>sudo nmcli connection modify &quot;FeatureDynamic&quot; ipv4.route-metric 100</span></span>
<span class="line"><span>sudo nmcli connection modify &quot;Wired connection 1&quot; +ipv4.routes &quot;192.168.1.195/32 0.0.0.0&quot;</span></span>
<span class="line"><span>sudo nmcli connection up &quot;Wired connection 1&quot;</span></span>
<span class="line"><span>sudo nmcli connection up &quot;FeatureDynamic&quot;</span></span></code></pre></div><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><p><strong>插上网线后 WiFi 无法上网 / SSH 断开</strong></p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p><strong>降低有线网卡优先级</strong>，<strong>提高 WiFi 优先级</strong>，<strong>删除有线网卡的默认网关</strong>（防止抢网），<strong>添加专属路由</strong>（强制 <code>192.168.1.195</code> 只走有线网卡），<strong>重启连接</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo nmcli connection modify &quot;Wired connection 1&quot; ipv4.route-metric 200</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo nmcli connection modify &quot;FeatureDynamic&quot; ipv4.route-metric 100</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo nmcli connection modify &quot;Wired connection 1&quot; ipv4.gateway &quot;&quot;</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo nmcli connection modify &quot;Wired connection 1&quot; +ipv4.routes &quot;192.168.1.195/32 0.0.0.0&quot;</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo nmcli connection up &quot;Wired connection 1&quot;</span></span>
<span class="line"><span>sudo nmcli connection up &quot;FeatureDynamic&quot;</span></span></code></pre></div></div></div>`,49)])])}const b=a(o,[["render",e]]);export{g as __pageData,b as default};
